UPDATE biz_workorder_insurance
SET
    option_json = CASE

        WHEN insurance_id = #{item.insuranceId}
        THEN #{item.optionJson}

    ELSE option_json
    END,
    deductible_option_json = CASE

        WHEN insurance_id = #{item.insuranceId}
        THEN #{item.deductibleOptionJson}

    ELSE deductible_option_json
    END,
    updated_by = #{updateBy}
WHERE
    workorder_id = #{workorderId}
    AND deleted = 0
    AND insurance_id IN

        #{item.insuranceId}
